1	/**
2	 * patron-anima clockwork engine.
3	 *
4	 * Between `inventory-check` and `decision-review`, consults a configured
5	 * Patron Anima to principle-check *every* decision the primer produced.
6	 * Under attended mode the primer contractually pre-fills `selected` on
7	 * every decision (so auto-acceptance never silently happens without
8	 * principle-check); patron-anima then reviews them all and confirms
9	 * (including `low`-confidence confirms), overrides, fills in, or
10	 * narrowly abstains.
11	 *
12	 * Abstention as absence — decision-review coupling:
13	 *   When the anima abstains on a decision (by omitting it from the
14	 *   emission array), `collect()` clears both `Decision.selected` and
15	 *   `Decision.patronOverride` on that decision. The engine relies on
16	 *   its consumer — `decision-review` — honouring the invariant that
17	 *   `selected === undefined` means "the decision still needs patron
18	 *   attention." Custom rigs that replace or precede `decision-review`
19	 *   must preserve this contract, or abstentions will silently
20	 *   auto-accept. `Decision.patron` is deliberately left alone so any
21	 *   prior verdict from a retry is preserved.
22	 *
23	 * Operational discipline (the tailored work prompt):
24	 *   The anima runs under a checked-in operational prompt — the static
25	 *   portions live in `patron-anima-prompt.md` (packaged alongside the
26	 *   plugin) and are loaded at startup; per-decision content (ids,
27	 *   questions, options, primer recommendations) is interpolated in this
28	 *   module at build time. The prompt encodes the engine's mode discipline,
29	 *   which is structurally distinct from the anima's taste (which lives in
30	 *   the role's system prompt):
31	 *
32	 *     - One option per decision. `selection` must be one of the offered
33	 *       option keys — no custom answers, no free-text, no multi-select.
34	 *     - Principle-structural confidence. `high` = a single principle from
35	 *       the role fires cleanly; `med` = multiple principles conflict and
36	 *       the anima resolves the conflict; `low` = no principle speaks and
37	 *       the anima confirms the primer's recommendation. `low` is a
38	 *       first-class emission path, not a placeholder and not reserved for
39	 *       abstention — principle-absence has the concrete meaning "no
40	 *       principled basis to differ; confirm the primer."
41	 *     - Narrow abstention by omission. The anima leaves a decision out of
42	 *       its emission array only in two cases: *irresolvable principle
43	 *       conflict* (multiple principles conflict and the anima cannot
44	 *       resolve without inventing a principle hierarchy the patron has
45	 *       not articulated) and *broken decision frame* (the question or
46	 *       options are incoherent as posed, so no valid emission would be
47	 *       faithful to the patron's intent). Every other case — including
48	 *       principle-absence — resolves to a first-class emission. The
49	 *       engine treats a missing verdict as "abstained": `selected` and
50	 *       `patronOverride` are cleared so `decision-review` surfaces the
51	 *       decision to the patron.
52	 *     - Out-of-lane prohibition. The draft worktree `cwd` passed to the
53	 *       anima permits filesystem access, but the prompt explicitly
54	 *       forbids file reads, grep, codebase audit, and second-guessing
55	 *       the primer's framing. The anima's entire input is the role's
56	 *       principles plus the decisions listed in the prompt.
57	 *
58	 * Config:
59	 *   guild.json["astrolabe"]["patronRole"]
60	 *     Qualified role name for the Patron Anima (e.g. 'guild.patron').
61	 *     When unset or empty, this engine no-ops — the pipeline proceeds
62	 *     exactly as it did before the engine existed. When set, the engine
63	 *     summons the anima whenever the plan has any decisions.
64	 *
65	 * Run → Collect protocol:
66	 *   run()     → loads the plan; when `patronRole` is set and the plan
67	 *                has at least one decision, builds a single prompt
68	 *                covering every decision and launches an anima session
69	 *                via `animator.summon()`. Returns
70	 *                `{ status: 'launched', sessionId }`. No-ops (completes
71	 *                with empty yields) when `patronRole` is unset/empty or
72	 *                the plan has no decisions.
73	 *   collect() → reads the session's `output` from Stacks, parses the
74	 *                emitted JSON verdict array, and for every decision on
75	 *                the plan either applies the anima's verdict
76	 *                (`selected` + `patron`, `patronOverride` cleared) or —
77	 *                if the decision is absent from the emission — clears
78	 *                `selected` and `patronOverride` so the decision
79	 *                surfaces to the patron via `decision-review`.
80	 *
81	 * Output contract (the anima is asked for):
82	 *   The session's final message must be a single fenced JSON block
83	 *   containing an array of verdict objects. Each object:
84	 *     - `id`         — the decision id
85	 *     - `verdict`    — 'confirm' | 'override' | 'fill-in'
86	 *     - `selection`  — one of the decision's offered option keys
87	 *     - `confidence` — 'high' | 'med' | 'low' (`low` = confirm the
88	 *                      primer on principle-absence; first-class emission)
89	 *     - `rationale`  — short free-text note (optional)
90	 *   Decisions the anima abstains on — the two narrow cases above — are
91	 *   absent from the array; the engine treats absence as
92	 *   "surface to patron" by clearing `selected` / `patronOverride`.
93	 *
94	 * Exhaustiveness:
95	 *   Single pass. Any decision not carrying a well-formed verdict —
96	 *   because the anima abstained (omitted it), emitted malformed JSON,
97	 *   picked an unknown option, or the session failed entirely — has
98	 *   `selected` and `patronOverride` cleared on the PlanDoc and flows
99	 *   to `decision-review` in the normal flow. The engine does not retry.
100	 */
101	
102	import { readFileSync } from 'node:fs';
103	import { dirname, resolve } from 'node:path';
104	import { fileURLToPath } from 'node:url';
105	
106	import { guild } from '@shardworks/nexus-core';
107	import type { EngineDesign, EngineRunContext, EngineRunResult } from '@shardworks/fabricator-apparatus';
108	import type { Book } from '@shardworks/stacks-apparatus';
109	import type { StacksApi } from '@shardworks/stacks-apparatus';
110	import type { AnimatorApi, SessionDoc } from '@shardworks/animator-apparatus';
111	import type { WritDoc } from '@shardworks/clerk-apparatus';
112	import { resolvePatronRole } from '../astrolabe.ts';
113	import type { Decision, PatronEmission, PlanDoc } from '../types.ts';
114	
115	// ── Prompt template ──────────────────────────────────────────────────
116	
117	const __filename = fileURLToPath(import.meta.url);
118	const __dirname = dirname(__filename);
119	
120	/**
121	 * The static portion of the patron-anima operational prompt, loaded at module
122	 * load time from the checked-in markdown file packaged alongside this plugin.
123	 * The sentinel `{{DECISIONS}}` is replaced by the per-decision listing at
124	 * prompt-build time. The markdown file lives at the package root so it is
125	 * reachable via the same relative path from both `src/engines/` (source
126	 * mode) and `dist/engines/` (published distribution).
127	 */
128	const PROMPT_TEMPLATE: string = readFileSync(
129	  resolve(__dirname, '../../patron-anima-prompt.md'),
130	  'utf-8',
131	);
132	
133	const DECISIONS_PLACEHOLDER = '{{DECISIONS}}';
134	
135	// ── Helpers ──────────────────────────────────────────────────────────
136	
137	/**
138	 * Assemble the patron work prompt from the plan's decisions.
139	 *
140	 * The static portion (preamble, mode discipline, out-of-lane prohibition,
141	 * output contract, worked example) lives in `patron-anima-prompt.md` and is
142	 * loaded into `PROMPT_TEMPLATE` at module load. This function renders each
143	 * decision — question, optional context, options, optional primer
144	 * recommendation / rationale — and substitutes the listing into the
145	 * template's `{{DECISIONS}}` placeholder.
146	 */
147	export function buildPatronPrompt(decisions: Decision[]): string {
148	  const lines: string[] = [];
149	
150	  for (const decision of decisions) {
151	    lines.push(`### ${decision.id}: ${decision.question}`);
152	    if (decision.context) {
153	      lines.push('');
154	      lines.push(`Context: ${decision.context}`);
155	    }
156	    lines.push('');
157	    lines.push('Options:');
158	    for (const [key, label] of Object.entries(decision.options)) {
159	      lines.push(`- \`${key}\` — ${label}`);
160	    }
161	    if (decision.recommendation) {
162	      lines.push('');
163	      const recLabel = decision.options[decision.recommendation] ?? decision.recommendation;
164	      lines.push(
165	        `Primer recommendation: \`${decision.recommendation}\` (${recLabel})`,
166	      );
167	      if (decision.rationale) {
168	        lines.push(`Primer rationale: ${decision.rationale}`);
169	      }
170	    } else {
171	      lines.push('');
172	      lines.push('Primer recommendation: (none — you must fill in)');
173	    }
174	    lines.push('');
175	  }
176	
177	  // Drop the trailing blank line so the substitution sits cleanly in the
178	  // template's final section.
179	  const decisionsBlock = lines.join('\n').replace(/\n+$/, '');
180	
181	  return PROMPT_TEMPLATE.replace(DECISIONS_PLACEHOLDER, decisionsBlock);
182	}
183	
184	/** Extract the last fenced JSON block from an anima's output. Returns null if none. */
185	export function extractJsonBlock(output: string): string | null {
186	  // Prefer ```json ... ``` fenced blocks; fall back to plain ``` ... ```.
187	  const jsonFence = /```(?:json)?\s*([\s\S]*?)```/gi;
188	  let match: RegExpExecArray | null;
189	  let last: string | null = null;
190	  while ((match = jsonFence.exec(output)) !== null) {
191	    last = match[1].trim();
192	  }
193	  if (last !== null) return last;
194	  // Last-ditch: try the output verbatim if it starts with `[` or `{`.
195	  const trimmed = output.trim();
196	  if (trimmed.startsWith('[') || trimmed.startsWith('{')) return trimmed;
197	  return null;
198	}
199	
200	export interface RawVerdict {
201	  id?: unknown;
202	  verdict?: unknown;
203	  selection?: unknown;
204	  confidence?: unknown;
205	  rationale?: unknown;
206	}
207	
208	/**
209	 * Parse the anima's JSON emission into a map keyed by decision id. Invalid
210	 * entries are dropped silently — the engine treats missing verdicts as
211	 * "leave the decision unfilled" and relies on `decision-review` to catch
212	 * them in the normal flow.
213	 */
214	export function parseEmission(
215	  output: string,
216	  decisions: Decision[],
217	): Map<string, PatronEmission> {
218	  const result = new Map<string, PatronEmission>();
219	  const block = extractJsonBlock(output);
220	  if (block === null) return result;
221	
222	  let parsed: unknown;
223	  try {
224	    parsed = JSON.parse(block);
225	  } catch {
226	    return result;
227	  }
228	
229	  // Accept either a bare array or an object with an `emissions` / `verdicts`
230	  // array field — be lenient about the outer shape so small model quirks
231	  // don't cost a whole round.
232	  let entries: unknown[];
233	  if (Array.isArray(parsed)) {
234	    entries = parsed;
235	  } else if (parsed && typeof parsed === 'object') {
236	    const obj = parsed as Record<string, unknown>;
237	    const maybe = obj.emissions ?? obj.verdicts ?? obj.decisions;
238	    entries = Array.isArray(maybe) ? maybe : [];
239	  } else {
240	    return result;
241	  }
242	
243	  const decisionById = new Map(decisions.map(d => [d.id, d]));
244	
245	  for (const rawEntry of entries) {
246	    if (!rawEntry || typeof rawEntry !== 'object') continue;
247	    const raw = rawEntry as RawVerdict;
248	    if (typeof raw.id !== 'string') continue;
249	    const decision = decisionById.get(raw.id);
250	    if (!decision) continue;
251	
252	    const verdict = raw.verdict;
253	    if (verdict !== 'confirm' && verdict !== 'override' && verdict !== 'fill-in') continue;
254	
255	    if (typeof raw.selection !== 'string') continue;
256	    if (!(raw.selection in decision.options)) continue;
257	
258	    const confidence = raw.confidence;
259	    if (confidence !== 'low' && confidence !== 'med' && confidence !== 'high') continue;
260	
261	    // `confirm` must agree with the primer's recommendation. If it doesn't,
262	    // treat the verdict as malformed — don't silently relabel it. Defends
263	    // against a model that says "confirm" but picks a different option.
264	    if (verdict === 'confirm') {
265	      if (!decision.recommendation || decision.recommendation !== raw.selection) {
266	        continue;
267	      }
268	    }
269	
270	    // `fill-in` requires there was no primer recommendation.
271	    if (verdict === 'fill-in' && decision.recommendation) {
272	      // Accept but only if the selection genuinely differs — otherwise
273	      // relabelling a confirm as fill-in is a model quirk we tolerate.
274	      // (Either way the `selected` resolution is the same.)
275	    }
276	
277	    // `override` requires a recommendation existed and differs from selection.
278	    if (verdict === 'override') {
279	      if (!decision.recommendation) continue;
280	      if (decision.recommendation === raw.selection) continue;
281	    }
282	
283	    const emission: PatronEmission = {
284	      verdict,
285	      selection: raw.selection,
286	      confidence,
287	    };
288	    if (typeof raw.rationale === 'string' && raw.rationale.length > 0) {
289	      emission.rationale = raw.rationale;
290	    }
291	    result.set(decision.id, emission);
292	  }
293	
294	  return result;
295	}
296	
297	// ── Engine factory ───────────────────────────────────────────────────
298	
299	export function createPatronAnimaEngine(getPlansBook: () => Book<PlanDoc>): EngineDesign {
300	  return {
301	    id: 'astrolabe.patron-anima',
302	
303	    async run(
304	      givens: Record<string, unknown>,
305	      context: EngineRunContext,
306	    ): Promise<EngineRunResult> {
307	      const planId = givens.planId;
308	      if (typeof planId !== 'string' || planId.length === 0) {
309	        throw new Error('patron-anima engine requires a non-empty string "planId" given.');
310	      }
311	
312	      const book = getPlansBook();
313	      const plan = await book.get(planId);
314	      if (!plan) {
315	        throw new Error(`Plan "${planId}" not found.`);
316	      }
317	
318	      // Skip-when-unset: no configured patron → no-op, decision-review
319	      // proceeds as it does today. The trim-and-check is shared with the
320	      // astrolabe.reader-analyst engine via `resolvePatronRole`.
321	      const role = resolvePatronRole();
322	      if (role === '') {
323	        return { status: 'completed', yields: {} };
324	      }
325	
326	      // Fast-path: no decisions on the plan → no-op. The primer emitted
327	      // nothing for the anima to weigh in on. (D13: keep this fast-path.)
328	      const decisions = plan.decisions ?? [];
329	      if (decisions.length === 0) {
330	        return { status: 'completed', yields: {} };
331	      }
332	
333	      const animator = guild().apparatus<AnimatorApi>('animator');
334	      const writ = givens.writ as WritDoc | undefined;
335	      const cwd =
336	        typeof givens.cwd === 'string' && givens.cwd.length > 0
337	          ? givens.cwd
338	          : process.cwd();
339	
340	      const prompt = buildPatronPrompt(decisions);
341	
342	      const handle = animator.summon({
343	        role,
344	        prompt,
345	        cwd,
346	        environment: writ ? { GIT_AUTHOR_EMAIL: `${writ.id}@nexus.local` } : {},
347	        metadata: {
348	          engineId: context.engineId,
349	          planId,
350	          ...(writ ? { writId: writ.id } : {}),
351	        },
352	      });
353	
354	      return { status: 'launched', sessionId: handle.sessionId };
355	    },
356	
357	    async collect(
358	      sessionId: string,
359	      givens: Record<string, unknown>,
360	      _context: EngineRunContext,
361	    ): Promise<unknown> {
362	      const planId = givens.planId;
363	      if (typeof planId !== 'string' || planId.length === 0) {
364	        throw new Error('patron-anima collect requires a non-empty string "planId" given.');
365	      }
366	
367	      const book = getPlansBook();
368	      const plan = await book.get(planId);
369	      if (!plan) {
370	        throw new Error(`Plan "${planId}" not found.`);
371	      }
372	
373	      const stacks = guild().apparatus<StacksApi>('stacks');
374	      const sessionsBook = stacks.readBook<SessionDoc>('animator', 'sessions');
375	      const session = await sessionsBook.get(sessionId);
376	      const output = session?.output ?? '';
377	
378	      const planDecisions = plan.decisions ?? [];
379	      const emissionsByDecisionId = parseEmission(output, planDecisions);
380	
381	      // Walk every decision on the plan. Decisions the anima emitted a
382	      // verdict for are stamped with `selected` + `patron`; decisions the
383	      // anima abstained on (absent from the emission map) have `selected`
384	      // and `patronOverride` cleared so decision-review's
385	      // `selected === undefined` filter surfaces them to the patron.
386	      // `Decision.patron` is deliberately left alone on abstention
387	      // (D14 leave-patron).
388	      const touched: string[] = [];
389	      const decisions = planDecisions.map(d => ({ ...d }));
390	      for (const decision of decisions) {
391	        const emission = emissionsByDecisionId.get(decision.id);
392	        if (emission) {
393	          decision.patron = emission;
394	          decision.selected = emission.selection;
395	          delete decision.patronOverride;
396	          touched.push(decision.id);
397	        } else {
398	          delete decision.selected;
399	          delete decision.patronOverride;
400	        }
401	      }
402	
403	      await book.patch(planId, {
404	        decisions,
405	        updatedAt: new Date().toISOString(),
406	      });
407	
408	      return {
409	        sessionId,
410	        touchedDecisionIds: touched,
411	        totalReviewable: planDecisions.length,
412	      };
413	    },
414	  };
415	}
416

